#!/usr/bin/env python3
"""Apply Update v4 - Rooms, Beds, Availability Map"""
import base64, os, sqlite3

PROJECT = os.path.expanduser("~/Desktop/dream-abroad")

files = {
    "backend/models.py": "",
    "backend/schemas.py": "",
    "backend/main.py": "",
    "backend/routers/transactions.py": "",
    "backend/routers/rooms.py": "",
    "frontend/vite.config.ts": "",
    "frontend/src/services/api.ts": "",
    "frontend/src/pages/TransactionsIn.tsx": "",
    "frontend/src/pages/Availability.tsx": "",
    "frontend/src/App.tsx": "",
    "frontend/src/components/Layout.tsx": "",
}

for rel_path, b64 in files.items():
    full = os.path.join(PROJECT, rel_path)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, "w") as f:
        f.write(base64.b64decode(b64).decode())
    print(f"Updated: {rel_path}")

# Fix api.ts baseURL
api_path = os.path.join(PROJECT, "frontend/src/services/api.ts")
with open(api_path, "r") as f:
    c = f.read()
if "localhost:8000" in c:
    c = c.replace("http://localhost:8000", "")
    with open(api_path, "w") as f:
        f.write(c)
    print("Fixed api.ts baseURL")

# Create new tables in SQLite
db_path = os.path.join(PROJECT, "backend", "dream_abroad.db")
if os.path.exists(db_path):
    conn = sqlite3.connect(db_path)
    cur = conn.cursor()
    # Create rooms table
    cur.execute("""
    CREATE TABLE IF NOT EXISTS rooms (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        property_id INTEGER NOT NULL REFERENCES properties(id),
        name VARCHAR(100) NOT NULL,
        room_type VARCHAR(20) DEFAULT 'individual',
        num_beds INTEGER DEFAULT 1,
        monthly_value FLOAT DEFAULT 0,
        notes TEXT,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )""")
    # Create beds table
    cur.execute("""
    CREATE TABLE IF NOT EXISTS beds (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        room_id INTEGER NOT NULL REFERENCES rooms(id),
        name VARCHAR(100) NOT NULL,
        monthly_value FLOAT DEFAULT 0,
        notes TEXT,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )""")
    # Add room_id and bed_id to clients if not exists
    try:
        cur.execute("ALTER TABLE clients ADD COLUMN room_id INTEGER")
        print("Added room_id to clients")
    except: pass
    try:
        cur.execute("ALTER TABLE clients ADD COLUMN bed_id INTEGER")
        print("Added bed_id to clients")
    except: pass
    # Add room_id and bed_id to transactions_in if not exists
    try:
        cur.execute("ALTER TABLE transactions_in ADD COLUMN room_id INTEGER")
        print("Added room_id to transactions_in")
    except: pass
    try:
        cur.execute("ALTER TABLE transactions_in ADD COLUMN bed_id INTEGER")
        print("Added bed_id to transactions_in")
    except: pass
    conn.commit()
    conn.close()
    print("Database updated!")
else:
    print("WARNING: Database not found at " + db_path)

print("\nDone! Restart backend and frontend.")
print("  Backend: cd ~/Desktop/dream-abroad/backend && lsof -ti:8000 | xargs kill -9; uvicorn main:app --reload")
print("  Frontend: restart will auto-reload via HMR")
